	"sap/suite/ui/commons/demo/tutorial/view/Jokers.view.xml":'﻿<mvc:View\n  xmlns:mvc="sap.ui.core.mvc"\n  xmlns="sap.m"\n  xmlns:core="sap.ui.core"\n  controllerName="sap.suite.ui.commons.demo.tutorial.controller.Jokers"><Page title="Jokerek" class="sapUiContentPadding jokerPage" showHeader="false"><VBox class="jokerShell" width="100%"><Title text="Jokerek" level="H2" class="sapUiTinyMarginBottom"/><Text text="Valassz egy jokert. Csempe kattintasra megnyilik a prompt oldal." class="jokerIntro sapUiSmallMarginBottom"/><HBox alignItems="Center" wrap="Wrap" class="sapUiSmallMarginBottom"><Label text="Tag szuro" class="sapUiTinyMarginEnd"/><Select width="14rem" selectedKey="{jokers>/activeTag}" change=".onTagFilterChange" items="{jokers>/availableTags}"><items><core:Item key="{jokers>}" text="{jokers>}"/></items></Select></HBox><FlexBox items="{jokers>/filteredTiles}" wrap="Wrap" class="jokerTileGrid"><items><GenericTile class="jokerTile" header="{jokers>title}" subheader="{= ${jokers>subtitle} + \' • \' + (${jokers>primaryTag} || \'Általános\') }" frameType="OneByOne" press=".onTilePress"><tileContent><TileContent footer="{jokers>footer}"><content><ImageContent src="sap-icon://ai"/></content></TileContent></tileContent></GenericTile></items></FlexBox></VBox></Page></mvc:View>\r\n\r\n',
	"sap/suite/ui/commons/demo/tutorial/view/Login.view.xml":'<mvc:View\n  xmlns:mvc="sap.ui.core.mvc"\n  xmlns="sap.m"\n  xmlns:form="sap.ui.layout.form"\n  controllerName="sap.suite.ui.commons.demo.tutorial.controller.Login"><Page title="Bejelentkezes" class="sapUiContentPadding loginPage"><VBox width="100%" alignItems="Center" justifyContent="Center"><Panel width="420px" headerText="Chatbot belepes" class="sapUiResponsiveMargin loginCard"><form:SimpleForm editable="true" layout="ResponsiveGridLayout" labelSpanXL="4" labelSpanL="4" labelSpanM="4" labelSpanS="12" adjustLabelSpan="false" emptySpanXL="0" emptySpanL="0" emptySpanM="0" emptySpanS="0" columnsXL="1" columnsL="1" columnsM="1" singleContainerFullSize="false"><Label text="Nev"/><Input value="{app>/loginName}" placeholder="HelloAdam"/><Label text="Jelszo"/><Input type="Password" value="{app>/loginPassword}" placeholder="Jelszo"/></form:SimpleForm><VBox class="sapUiSmallMarginTop"><Button text="Belepes" type="Emphasized" press=".onLogin" width="100%"/></VBox></Panel></VBox></Page></mvc:View>\n',
